class RecommendationService:
    def recommend(self, user: User) -> list[str]:
        orders = OrderRepository().for_user(user)
        if is_premium(user) and len(orders) > 1:
            return ["bundle_plus", "priority_delivery"]
        return ["starter_bundle"]

